11	library ieee;
12	    use ieee.std_logic_1164.all;
13	    use ieee.numeric_std.all;
14	    
15	library work;
16	    use work.psi_common_array_pkg.all;
17	    use work.psi_common_math_pkg.all;
18	    use work.data_rec_register_pkg.all;
19	
20	------------------------------------------------------------------------------
21	-- Entity
22	------------------------------------------------------------------------------	
23	entity data_rec is
24	    generic
25	    (
26	        -- Component Parameters	
27	        NumOfInputs_g				: positive range 1 to 8	:= 4;
28	        InputWidth_g				: positive				:= 8;
29	        MemoryDepth_g				: positive				:= 128;
30	        TrigInputs_g				: natural range 0 to 8	:= 1
31	    );
32	    port
33	    (
34	        -- Control Signals
35	        Clk							: in std_logic;
36	        Rst							: in std_logic;
37	        -- Data Ports
38	        In_Data0					: in std_logic_vector(InputWidth_g-1 downto 0);
39	        In_Data1					: in std_logic_vector(InputWidth_g-1 downto 0);
40	        In_Data2					: in std_logic_vector(InputWidth_g-1 downto 0);
41	        In_Data3					: in std_logic_vector(InputWidth_g-1 downto 0);
42	        In_Data4					: in std_logic_vector(InputWidth_g-1 downto 0);
43	        In_Data5					: in std_logic_vector(InputWidth_g-1 downto 0);
44	        In_Data6					: in std_logic_vector(InputWidth_g-1 downto 0);
45	        In_Data7					: in std_logic_vector(InputWidth_g-1 downto 0);
46	        In_Vld						: in std_logic;
47	        -- Trigger Ports
48	        Trig_In						: in std_logic_vector(TrigInputs_g-1 downto 0);
49	        Trig_Out					: out std_logic;                                           -- Optional output for trigger sharing
50	        -- Register Ports
51	        State						: out std_logic_vector(3 downto 0);							-- Status of the recorder
52	        Arm							: in std_logic;												-- Arm the recorder
53	        Ack							: in std_logic;												-- Acknowledge data reatout
54	        PreTrigSpls					: in std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);	-- Number of pre trigger samples 
55	        TotalSpls					: in std_logic_vector(log2ceil(MemoryDepth_g) downto 0);	-- Number of total samples
56	        SelfTrigLo					: in std_logic_vector(InputWidth_g-1 downto 0);				-- Self triggering mask, lower limit
57	        SelfTrigHi					: in std_logic_vector(InputWidth_g-1 downto 0);				-- Self triggering mask, upper limit
58	        SelfTrigChEna				: in std_logic_vector(NumOfInputs_g-1 downto 0);			-- Enable self triggering analysis 
59	        SelfTrigOnExit				: in std_logic;												-- Trigger if signal leaves the configured range
60	        SelfTrigOnEnter				: in std_logic;												-- Trigger if signal enters the configured range	
61	        SwTrig						: in std_logic;												-- Force trigger from software		
62	        Done						: out std_logic;											-- A data recording was completed
63	        TrigCntClr					: in std_logic;												-- Clear trigger counter
64	        TrigCnt						: out std_logic_vector(31 downto 0);						-- Trigger counter output
65	        DoneTime					: out std_logic_vector(31 downto 0);						-- Time spent in done status
66	        TrigEna						: in std_logic_vector(2 downto 0);							-- Trigger source enable
67	        EnableExtTrig				: in std_logic_vector(TrigInputs_g-1 downto 0);				-- External trigger enabled (triggers are ORed)
68	        MinRecPeriod				: in std_logic_vector(31 downto 0);							-- Minimum period between two recordings in clock cycles
69	        -- Memory Ports
70	        Mem_Wr						: out std_logic;
71	        Mem_Adr						: out std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0);
72	        Mem_Data					: out std_logic_vector(NumOfInputs_g*InputWidth_g-1 downto 0);
73	        FirstSplAddr				: out std_logic_vector(log2ceil(MemoryDepth_g)-1 downto 0)	-- Address of the first sample in the recording buffer
74	    );
75	
76	end entity data_rec;
77	
78	------------------------------------------------------------------------------
79	-- Architecture section
80	------------------------------------------------------------------------------
81	
82	architecture rtl of data_rec is 
83	    -- More complex logic is required to support non-power-of-two recorder depth
84	    constant NonPwr2MemDepth_c				: boolean				:= (log2(MemoryDepth_g) /= log2ceil(MemoryDepth_g));
85	    
86	    -- 2D array handling
87	    type Data_t is array(natural range <>) of std_logic_vector(InputWidth_g-1 downto 0);
88	    signal In_Data 		: Data_t(7 downto 0);
89	    type TrigIn_t is array(natural range <>) of std_logic_vector(TrigInputs_g-1 downto 0);
90	
91	    -- State defintion
92	    type State_t is (Idle_s, PreTrig_s, WaitTrig_s, PostTrig_s, Done_s);
93	
94	    -- Two Process Method
95		type data_rec_r is record
96			-- Input Registers
97			In_Vld				: std_logic_vector(0 to 2);
98			Trig_In				: TrigIn_t(0 to 2);
99			Data_0				: Data_t(NumOfInputs_g-1 downto 0);
100			Data_1				: Data_t(NumOfInputs_g-1 downto 0);
101			Data_2				: Data_t(NumOfInputs_g-1 downto 0);
102			Data_3				: Data_t(NumOfInputs_g-1 downto 0);
103			-- Status	
104			State_2				: State_t;
105			Trigger_2			: std_logic;
106			AdrCnt_2			: unsigned(Mem_Adr'range);
107			AdrCnt_3			: unsigned(Mem_Adr'range);
108			SplCnt_2			: unsigned(Mem_Adr'high+1 downto 0);
109			Done				: std_logic_vector(2 to 3);
110			MemWr_3				: std_logic;
111			TrigCnt_3			: unsigned(31 downto 0);
112			DoneTime_3			: unsigned(31 downto 0);
113			FirstSpl_3			: unsigned(Mem_Adr'range);
114			StInRange_1			: std_logic_vector(NumOfInputs_g-1 downto 0);
115			StInRangeLast_1		: std_logic_vector(NumOfInputs_g-1 downto 0);
116			LastRecCnt_2		: std_logic_vector(31 downto 0);
117			-- Configuration 
118			SwTrigPending_2		: std_logic;
119			ExtTrigPending_2	: std_logic;
120			-- Trigger Output
121			Trig_Out            : std_logic;  
122	    end record;	
123	    signal r, r_next : data_rec_r;
124	    
125	
126	begin
127	    --------------------------------------------------------------------------
128	    -- 2D array handling
129	    --------------------------------------------------------------------------
130	    In_Data(0)	<= In_Data0;
131	    In_Data(1)	<= In_Data1;
132	    In_Data(2)	<= In_Data2;
133	    In_Data(3)	<= In_Data3;
134	    In_Data(4)	<= In_Data4;
135	    In_Data(5)	<= In_Data5;
136	    In_Data(6)	<= In_Data6;
137	    In_Data(7)	<= In_Data7;
138	
139	    --------------------------------------------------------------------------
140	    -- Combinatorial Process
141	    --------------------------------------------------------------------------
142	    p_comb : process(	r, In_Data, In_Vld, Trig_In,
143	                        Arm, PreTrigSpls, TotalSpls, SelfTrigLo, SelfTrigHi, 
144	                        SelfTrigChEna, SelfTrigOnExit, SelfTrigOnEnter, SwTrig, Ack,
145	                        TrigCntClr, MinRecPeriod, EnableExtTrig)	
146	        variable v : data_rec_r;
147	        variable StEnter_2	: std_logic_vector(NumOfInputs_g-1 downto 0);
148	        variable StExit_2	: std_logic_vector(NumOfInputs_g-1 downto 0);
149	        variable StTrig_2	: std_logic;
150	        variable TrigNow_2	: std_logic;
151	    begin
152	        -- hold variables stable
153	        v := r;
154	        
155	        -- *** Pipe Handling ***
156	        v.In_Vld(v.In_Vld'low+1 to v.In_Vld'high) 		:= r.In_Vld(r.In_Vld'low to r.In_Vld'high-1);
157	        v.Trig_In(v.Trig_In'low+1 to v.Trig_In'high) 	:= r.Trig_In(r.Trig_In'low to r.Trig_In'high-1);
158	        v.Done(v.Done'low+1 to v.Done'high) 			:= r.Done(r.Done'low to r.Done'high-1);
159	        
160	        -- *** Stage 0 ***
161	        -- Input Registers
162	        v.In_Vld(0)		:= In_Vld;
163	        v.Trig_In(0)	:= Trig_In;
164	        for i in 0 to NumOfInputs_g-1 loop
165	            v.Data_0(i) := In_Data(i);
166	        end loop;
167	        
168	        -- *** Stage 1 ***
169	        -- Pipelining
170	        v.Data_1 := r.Data_0;
171	        
172	        -- Self Trigger In Range detection
173	        if r.In_Vld(0) = '1' then
174	            v.StInRangeLast_1 := r.StInRange_1;
175	            for i in 0 to NumOfInputs_g-1 loop
176	                -- unsigned in range
177	                if 	(unsigned(r.Data_0(i)) <= unsigned(SelfTrigHi)) and
178	                    (unsigned(r.Data_0(i)) >= unsigned(SelfTrigLo)) then
179	                    v.StInRange_1(i) := '1';
180	                -- signed in range
181	                elsif (signed(r.Data_0(i)) <= signed(SelfTrigHi)) and
182	                      (signed(r.Data_0(i)) >= signed(SelfTrigLo)) then	
183	                    v.StInRange_1(i) := '1';
184	                else	
185	                    v.StInRange_1(i) := '0';
186	                end if;
187	            end loop;
188	        end if;
189	        
190	        -- *** SW Trigger Pending detection ***
191	        
192	        -- *** Stage 2 ***
193	        -- Pipelining
194	        v.Data_2 := r.Data_1;
195	        
196	        -- Self Trigger
197	        StEnter_2 	:= r.StInRange_1 and not r.StInRangeLast_1;
198	        StExit_2 	:= r.StInRangeLast_1 and not r.StInRange_1;
199	        StTrig_2	:= '0';
200	        if (SelfTrigOnExit = '1') and (unsigned(StExit_2 and SelfTrigChEna) /= 0) then
201	            StTrig_2	:= '1';
202	        end if;
203	        if (SelfTrigOnEnter = '1') and (unsigned(StEnter_2 and SelfTrigChEna) /= 0) then
204	            StTrig_2	:= '1';
205	        end if;
206	        
207	        -- External Trigger
208	        if r.State_2 = PreTrig_s then
209	            v.ExtTrigPending_2 := '0';
210	        end if;			
211	        for i in 0 to TrigInputs_g-1 loop
212	            if r.Trig_In(0)(i) = '1' and r.Trig_In(1)(i) = '0' and EnableExtTrig(i) = '1' then
213	                v.ExtTrigPending_2 := '1';
214	            end if;		
215	        end loop;
216	        
217	        -- SW Trigger
218	        if SwTrig = '1' then
219	            v.SwTrigPending_2 := '1';
220	        elsif r.State_2 = PreTrig_s then
221	            v.SwTrigPending_2 := '0';
222	        end if;
223	
224	        -- Trigger Masking		
225	        TrigNow_2 := ((StTrig_2 and TrigEna(Reg_TrigEna_SelfIdx_c)) or 
226	                      (r.ExtTrigPending_2 and TrigEna(Reg_TrigEna_ExtIdx_c)) or 	-- Edge sensitive trigger
227	                      (r.SwTrigPending_2 and TrigEna(Reg_TrigEna_SwIdx_c)))
228	                     and r.In_Vld(1);
229	                     
230	        -- Maximum trigger period counter
231	        if unsigned(MinRecPeriod) < unsigned(r.LastRecCnt_2) then
232	            v.LastRecCnt_2 := MinRecPeriod;
233	        elsif unsigned(r.LastRecCnt_2) /= 0 then
234	            TrigNow_2 := '0';
235	            v.LastRecCnt_2 := std_logic_vector(unsigned(r.LastRecCnt_2) - 1);
236	            -- clear pendign triggers (they were too early)
237	            v.ExtTrigPending_2 := '0'; 
238	            v.SwTrigPending_2 := '0';
239	        elsif r.Trigger_2 = '1' then
240	            v.LastRecCnt_2 := MinRecPeriod;
241	        end if;						 
242	                     
243	        -- Recorder state handling
244	        v.Trigger_2 := '0';
245	        v.Done(2)	:= '0';
246	        case r.State_2 is
247	            when Idle_s =>					
248	                if (Arm = '1') then
249	                    v.State_2	:= PreTrig_s;
250	                end if;
251	            when PreTrig_s => 
252	                -- Skip if no pre trigger is required
253	                if unsigned(PreTrigSpls) = 0 then
254	                    v.State_2 := WaitTrig_s;
255	                -- Pre trigger recorded
256	                elsif (r.AdrCnt_2 = unsigned(PreTrigSpls)-1) and (r.In_Vld(1) = '1') then
257	                    v.State_2 := WaitTrig_s;
258	                end if;
259	            when WaitTrig_s =>
260	                if TrigNow_2 = '1' then
261	                    v.State_2 	:= PostTrig_s;
262	                    v.Trigger_2 := '1';
263	                end if;
264	            when PostTrig_s => 
265	                if r.SplCnt_2 >= unsigned(TotalSpls) then
266	                    v.State_2 	:= Done_s;
267	                    v.Done(2)	:= '1';
268	                    end if;
269	            when Done_s =>				
270	                if Arm = '1' then
271	                    v.State_2 := PreTrig_s;
272	                elsif Ack = '1' then
273	                    v.State_2 := Idle_s;				
274	                end if;			
275	            when others => null;
276	        end case;
277	                        
278	        -- Address coutner handling
279	        if (r.State_2 = Idle_s) or (r.State_2 = Done_s)  then
280	            v.AdrCnt_2	:= (others => '0');
281	        elsif r.In_Vld(1) = '1' then
282	            if r.AdrCnt_2 = MemoryDepth_g-1 then
283	                v.AdrCnt_2 := (others => '0');
284	            else
285	                v.AdrCnt_2	:= r.AdrCnt_2+1;
286	            end if;
287	        end if;
288	        
289	        -- Sample Counter handling
290	        if r.State_2 = WaitTrig_s then
291	            v.SplCnt_2 := unsigned('0' & PreTrigSpls) + 1;
292	        elsif r.In_Vld(1) = '1' then
293	            v.SplCnt_2 := r.SplCnt_2 + 1;
294	        end if;
295	        
296	        -- *** Stage 3 ***
297	        -- Pipelining
298	        v.Data_3 	:= r.Data_2;
299	        v.AdrCnt_3 	:= r.AdrCnt_2;
300	        
301	        -- memory write
302	        if (r.State_2 = Idle_s) or (r.State_2 = Done_s) then
303	            v.MemWr_3	:= '0';
304	        else	
305	            v.MemWr_3	:= r.In_Vld(2);
306	        end if;
307	        
308	        -- first sample address
309	        if r.Trigger_2 = '1' then
310	            -- simple logic for power of 2 recorder depth
311	            if not NonPwr2MemDepth_c then
312	                v.FirstSpl_3	:= r.AdrCnt_2-unsigned(PreTrigSpls);
313	            -- more complex logic for non-power of two recorder depth
314	            else
315	                if r.AdrCnt_2 > unsigned(PreTrigSpls) then
316	                    v.FirstSpl_3	:= r.AdrCnt_2-unsigned(PreTrigSpls);
317	                else
318	                    v.FirstSpl_3	:= r.AdrCnt_2-unsigned(PreTrigSpls) + MemoryDepth_g;
319	                end if;
320	            end if;
321	        end if;
322	        
323	        -- trigger counter
324	        if TrigCntClr = '1' then
325	            v.TrigCnt_3		:= (others => '0');
326	        elsif r.Trigger_2 = '1' then	
327	            v.TrigCnt_3		:= r.TrigCnt_3+1;
328	        end if;
329	        
330	        -- Done time counter
331	        if r.Trigger_2 = '1' then
332	            v.DoneTime_3 := (others => '0');
333	        elsif r.State_2 = Done_s then
334	            if r.DoneTime_3 /= X"FFFFFFFF" then 	-- prevent overflow
335	                v.DoneTime_3 := r.DoneTime_3 + 1;
336	            end if;
337	        end if;
338	        
339	        -- Outputs
340	        case r.State_2 is
341	            when Idle_s 	=>	State <= std_logic_vector(to_unsigned(Reg_Stat_StateIdle_c, State'length));
342	            when PreTrig_s 	=>	State <= std_logic_vector(to_unsigned(Reg_Stat_StatePreTrig_c, State'length));
343	            when WaitTrig_s =>	State <= std_logic_vector(to_unsigned(Reg_Stat_StateWaitTrig_c, State'length));
344	            when PostTrig_s =>	State <= std_logic_vector(to_unsigned(Reg_Stat_StatePostTrig_c, State'length));
345	            when Done_s 	=>	State <= std_logic_vector(to_unsigned(Reg_Stat_StateDone_c, State'length));
346	            when others 	=>	State <= (others => '0');
347	        end case; 
348	        for i in 0 to NumOfInputs_g-1 loop 
349	            Mem_Data((i+1)*InputWidth_g-1 downto i*InputWidth_g) <= r.Data_3(i);
350	        end loop;
351	        Mem_Adr <= std_logic_vector(r.AdrCnt_3);
352	        Mem_Wr <= r.MemWr_3;
353	        FirstSplAddr <= std_logic_vector(r.FirstSpl_3);
354	        Done <= r.Done(3);
355	        TrigCnt <= std_logic_vector(r.TrigCnt_3);
356	        DoneTime <= std_logic_vector(r.DoneTime_3);  
357	        
358	        -- Apply to record
359	        r_next <= v;
360	        
361	    end process;
362	    
363	    --------------------------------------------------------------------------
364	    -- Sequential Process
365	    --------------------------------------------------------------------------	
366	    p_seq : process(Clk)
367	    begin	
368	        if rising_edge(Clk) then
369	            r <= r_next;
370	            if Rst = '1' then
371	                r.In_Vld			<= (others => '0');
372	                r.Trig_In			<= (others => (others => '0'));
373	                r.State_2			<= Idle_s;
374	                r.AdrCnt_2			<= (others => '0');
375	                r.SplCnt_2			<= (others => '0');
376	                r.MemWr_3			<= '0';
377	                r.Trigger_2			<= '0';
378	                r.FirstSpl_3		<= (others => '0');
379	                r.SwTrigPending_2	<= '0';
380	                r.Done				<= (others => '0');
381	                r.TrigCnt_3			<= (others => '0');
382	                r.DoneTime_3		<= (others => '0');
383	                r.ExtTrigPending_2	<= '0';
384	                r.LastRecCnt_2		<= (others => '0');
385	            end if;
386	        end if;
387	    end process;
388	
389		----------------------------------------------------------------------------
390		-- Output assignment
391		----------------------------------------------------------------------------
392		-- Trigger output
393		Trig_Out <= r.Trigger_2;
394	 
395	end rtl;

